+/**
+ * Replaces recursive placeholders in a schema graph.
+ *
+ * @param value The value to be copied.
+ * @param schema The recursive schema.
+ *
+ * @returns A copy with recursive placeholders replaced.
+ *
+ * @internal
+ */
+function _replaceRecur<TValue>(value: TValue, schema: unknown): TValue {
+  const references = new Map<object, object>();
+
+  function replace<TValue>(value: TValue): TValue {
+    if (value === Recur) {
+      return schema as TValue;
+    }
+    if (!value || typeof value !== 'object') {
+      return value;
+    }
+    const existing = references.get(value);
+    if (existing) {
+      return existing as TValue;
+    }
+    const copy = Array.isArray(value)
+      ? []
+      : Object.create(Object.getPrototypeOf(value));
+    references.set(value, copy);
+    for (const key of Reflect.ownKeys(value)) {
+      const descriptor = Object.getOwnPropertyDescriptor(value, key)!;
+      if ('value' in descriptor) {
+        descriptor.value = replace(descriptor.value);
+      }
+      Object.defineProperty(copy, key, descriptor);
+    }
+    return copy;
+  }
+
+  return replace(value);
